const strategy = $('Strategy Agent').item.json.candidates[0].content.parts[0].text;
const optimisation = $('Optimisation Agent').item.json.candidates[0].content.parts[0].text;
const compliance = $('Compliance Agent').item.json.candidates[0].content.parts[0].text;

const strategyData = JSON.parse(strategy);
const optimisationData = JSON.parse(optimisation);
const complianceData = JSON.parse(compliance);

const report = {
  date: new Date().toISOString().split('T')[0],
  account_id: $env.META_AD_ACCOUNT_ID,
  strategy: strategyData,
  optimisation: optimisationData,
  compliance: complianceData,
  generated_at: new Date().toISOString()
};

// Format Slack message
const slackText = [
  `*📊 Laiqa Daily Growth Report - ${report.date}*`,
  `*Strategy Summary:* ${strategyData.summary}`,
  `*Top Issues:* ${(strategyData.top_issues || []).join(', ')}`,
  `*Proposed Actions:* ${optimisationData.actions?.length || 0} actions queued`,
  `*Compliance:* ${complianceData.overall_status}`,
  `*Confidence:* ${Math.round((strategyData.confidence || 0) * 100)}%`
].join('\n');

return [{ json: { report, slackText } }];
